// 세션 사용자
var mem = $c.data.getMemInfo($p);
scwin.userId = mem && mem.userId ? mem.userId : "";

// 서버일자
scwin.strCurDate = $c.date.getServerDateTime($p, "yyyyMMdd");

// JSP 전역 변수/상수 매핑
scwin.MSG_LO_WRN_007 = "Customer와 Dept가 일치하지 않습니다. \n거래처별 매출귀속 정의 화면에서 정보를 확인하세요.";
scwin.MSG_LO_WRN_008 = "이미 전표가 발행  되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_009 = "Department 가 변경 되었습니다.";
scwin.statusFlag = ""; //수정/등록 Flag(C:Regist, U:Update,I:Init)
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.mhnoFlag = "0"; // 1일때 mhno onloadComplete후 조회.

scwin.v_linkcheck = null;
scwin.v_kcomcd = null; // hd_kcomcd
scwin.v_blno = null;
scwin.v_mhno = null;
scwin.v_bkno = null;
scwin.v_carrierBkno = null;

// 추가 
scwin.v_elno = null;

// 히든
scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "O";
scwin.ed_carrierBkNo = "";

// onpageload
scwin.onpageload = function () {
  // 파라미터 세팅
  scwin.v_linkcheck = $c.data.getParameter($p, "linkcheck") || "0";
  scwin.v_kcomcd = $c.data.getParameter($p, "kcomcd") || "";
  scwin.v_blno = $c.data.getParameter($p, "blno") || "";
  scwin.v_mhno = $c.data.getParameter($p, "mhno") || "";
  scwin.v_bkno = $c.data.getParameter($p, "bkno") || "";
  scwin.v_carrierBkno = $c.data.getParameter($p, "carrierBkno") || "";
  const codeOptions = [{
    grpCd: "IL005",
    compID: "lc_hhincoterm"
  } //열위치
  // , { grpCd: "FI006", compID: "gr_region:acctSummaryCd" }  //적요위치
  ];
  $c.data.setCommonCode($p, codeOptions);
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = async function () {
  scwin.f_initSetTab(); //tab세팅
  scwin.f_DefaultValue();
  scwin.f_Check();
  await scwin.f_ContainerTypeLoading(); // Container Type 정보
  await scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리
  scwin.f_header();
};

//--------------------------------------------------------------------------
// header dataset 초기화
//--------------------------------------------------------------------------
scwin.f_header = function () {
  // ds_condition_path
  if (ds_condition_path.getRowCount() == 0) {
    ds_condition_path.insertRow(0);
  }
  // ds_result_path 컬럼은 dataList 정의로 대체
};

//---------------------------------------------------------
// Parameter Setting
// 다른 화면에서 들어올때 각 화면별 조건을 받아서 조회한다.
//---------------------------------------------------------
scwin.f_getParametrSetting = async function (gubun) {
  switch (gubun) {
    case "0":
      break;
    case "1": // Booking Search Grid
    case "2":
      // House Search
      scwin.mhnoFlag = "1";
      if ($c.util.isEmpty($p, scwin.v_blno)) {
        cnd_ed_hhblno.setValue("");
        cnd_ed_hhblno.focus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_hhblno.setValue(scwin.v_blno);
      if (ds_hmhno.getRowCount() == 0) {
        ds_hmhno.insertRow(0);
      }
      ds_hmhno.setCellData(0, "code", scwin.v_mhno);
      ds_hmhno.setCellData(0, "name", scwin.v_mhno);
      cnd_lc_mhno.focus();
      break;
    case "4":
      // Booking 화면에서 create
      await scwin.f_Create();
      ed_hhbkgno.setValue(scwin.v_bkno);
      cnd_ed_hhblno.focus();
      tbc_main.setSelectedTabIndex(0);
      ed_hhbkgno.focus();
      ed_hhetd.focus();
      lc_hhbkgseq.focus();

      // 2020.03.02 ITEM 자동 세팅
      if (txt_hhmitem1.getValue() == "") {
        //부킹정보에 아이템 코드없이 아이템 명으로 등록 된 경우가 있으므로 코드값이 아닌 명으로 체크
        ed_hhitem.setValue("30000000");
        // scwin.f_OpenCommonPopUp("Item", "T", "F", "F");
        await scwin.f_OpenCommonPopUpAsync("Item", "T", "F", "F");
      }
      txt_blpic.setValue("");
      //기본으로 등록자 ID 기입 처리
      if (ed_blpic.getValue() == "") {
        ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
        // scwin.f_PopUp("B/L PIC", "T");
        await scwin.f_PopUpAsync("B/L PIC", "T");
      }
      await scwin.ed_hhbkgno_onblur();
      lc_hhprenm.setSelectedIndex(0);
      break;
  }
};

// scwin.f_getParametrSetting("4")일 경우 팝업 비동기로 오픈되게함
scwin.f_OpenCommonPopUpAsync = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
  return new Promise(resolve => {
    if (gubun1 === "Item") {
      udc_hhitem.setSelectId("retrieveCommGoodsInfo");
      udc_hhitem.ilCommonPopUp(function (ret) {
        $c.gus.cfSetReturnValue($p, ret, ed_hhitem, txt_hhmitem1);
        resolve(ret);
      }, ed_hhitem.getValue().trim(), txt_hhmitem1.getValue(), pWinCloseTF, '2', "Code, Name", '80,230', "3,4,5,6,7,8,9,10", null, null, null, null, null, null, pAllSearchTF, "Item,Code,Name", pNoDataCloseTF);
    }
  });
};

// scwin.f_getParametrSetting("4")일 경우 팝업 비동기로 오픈되게함
scwin.f_PopUpAsync = function (disGubun, chgGubun) {
  return new Promise(resolve => {
    switch (disGubun) {
      case "B/L PIC":
        udc_blpic.setSelectId("retrieveEmpInfo");
        udc_blpic.ilCommonPopUp(function (ret) {
          $c.gus.cfSetReturnValue($p, ret, ed_blpic, txt_blpic);
          resolve(ret);
        }, ed_blpic.getValue().trim(), txt_blpic.getValue(), "T", '4', "B/L PIC", '100,350', null, null, '500', '500', null, null, null, "F", null);
        break;
      default:
        resolve(null);
        break;
    }
  });
};

//---------------------------------------------------------
// Object Check (statusFlag 에 따른 초기값)
