//---------------------------------------------------------
// 상태별 화면 제어
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      $c.gus.cfDisableKeyData($p); /// Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Cancel, btn_FileDownload, btn_Save, btn_Delete, btn_Update, btn_1, btn_2, btn_3, btn_4, btn_5, btn_6, btn_7, btn_8, btn_CntrReceive, btn_AddRow1, btn_AddCntr, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, pu_departmentChange, txt_hhmitem1]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_9]);
      scwin.f_DisablePopUpObj();
      ed_eltotwgt.setReadOnly(true);
      // 검색영역 enable
      $c.gus.cfEnableObjects($p, [tbl_Search]); // 조회조건.

      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      $c.gus.cfDisableKeyData($p);
      scwin.f_DisablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, btn_CntrReceive, btn_AddRow1, btn_AddCntr, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, txt_hhmitem1]);
      $c.gus.cfEnableBtnOnly($p, [btn_Copy, btn_Create, btn_Delete, btn_FileDownload, btn_4, btn_5, btn_6, btn_7, btn_8, btn_9, pu_departmentChange]);

      // 그리드 readOnly : 수정 불가 
      scwin.f_setGridColumnsReadOnly(gr_ocContList, true);
      scwin.f_setGridColumnsReadOnly(gr_ocElList, true);
      ed_eltotwgt.setReadOnly(false);
      if (scwin.statusFlag == "C") {
        $c.gus.cfDisableBtnOnly($p, [btn_Update]);
      } else {
        $c.gus.cfEnableBtnOnly($p, [btn_Update]);
      }
      // 검색영역 enable
      $c.gus.cfEnableObjects($p, [tbl_Search]); // 조회조건.
      scwin.statusFlag = ""; // flag null
      break;
    case "CREATE":
      $c.gus.cfEnableKeyData($p);
      scwin.f_EnablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Create, btn_Update, btn_Delete, btn_4, btn_5, btn_6, btn_7, btn_8, pu_departmentChange, txt_hhmitem1]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_FileDownload, btn_1, btn_2, btn_3, btn_9, btn_CntrReceive, btn_AddRow1, btn_AddCntr, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);

      // 그리드 readOnly : 수정 가능  
      ed_eltotwgt.setReadOnly(false);
      scwin.f_setGridColumnsReadOnly(gr_ocContList, false);
      scwin.f_setGridColumnsReadOnly(gr_ocElList, false);
      $c.gus.cfDisableObjects($p, [tbl_Search]); // 조회조건.
      $c.gus.cfEnableObjects($p, [cnd_ed_hhblno, cnd_lc_autono]); // 조회조건.
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Update, btn_Create, btn_Delete, btn_4, btn_5, btn_6, btn_7, btn_8, pu_departmentChange]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_FileDownload, btn_1, btn_2, btn_3, btn_9, btn_CntrReceive, btn_AddRow1, btn_AddCntr, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, txt_hhmitem1, txt_hhmitem2]);
      $c.gus.cfDisableKey($p);
      scwin.f_EnablePopUpObj();
      ed_eltotwgt.setReadOnly(false);

      // 그리드 readOnly : 수정 가능  
      scwin.f_setGridColumnsReadOnly(gr_ocContList, false);
      scwin.f_setGridColumnsReadOnly(gr_ocElList, false);
      $c.gus.cfDisableObjects($p, [tbl_Search]);
      scwin.statusFlag = "U";
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Delete, btn_Cancel, btn_FileDownload]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Create]);
      ed_eltotwgt.setReadOnly(false);
      scwin.f_Set("RETRIEVE");
      break;
  }
};

