//---------------------------------------------------------
// 저장
// 1. HOUSE B/L NO 를 DBEX로 시작하는 자동 NUMBERING 
// 2. HOUSE HEADER를 생성한다.
// 3. UPDATE 모드로 CONTAINER 및 적하목록을 등록한다.
// MARK, DISCRIPTION은 CLOB으로 이루어져 있다.
//---------------------------------------------------------
scwin.f_Save = async function () {
  if (ds_houseblList.getModifiedIndex().length == 0 && ds_ocContList.getModifiedIndex().length == 0 && ds_ocElList.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["House B/L"]); // @은(는) 변경된 사항이 없습니다
    return;
  }
  if (!(await scwin.f_validate())) return;
  var ok = await $c.win.confirm($p, E_MSG_CM_CRM_001); // "저장하시겠습니까?"
  if (!ok) return;
  if (scwin.statusFlag == "C") {
    // DBEX
    if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
      // House B/L NO 를 생성및 가져온다.(creadyDt로 번호 생성)
      ds_retrieve.set("hhetd", ds_houseblList.getCellData(0, "creadyDt") || "");
      let e = await $c.sbm.execute($p, sbm_retrievehouseBlNo);

      // if (ds_retrieveNo.getRowCount() > 0) {
      if (e.responseJSON.OUT_DS1.length > 0) {
        var newNo = ds_retrieveNo.getCellData(0, "hhblno");
        cnd_ed_hhblno.setValue(newNo);
      }
    }
    ds_houseblList.setCellData(0, "kcomcd", scwin.hd_kcomcd);
    ds_houseblList.setCellData(0, "hhblno", cnd_ed_hhblno.getValue() || "");
    ds_houseblList.setCellData(0, "hhbkgseq", lc_hhbkgseq.getValue() || "");
    ds_houseblList.setCellData(0, "mhno", cnd_lc_mhno.getValue() || "");
    ds_houseblList.setCellData(0, "hhisunm", lc_hhisunm.getValue() || "");
    ds_houseblList.setCellData(0, "hhpaynm", lc_hhpaynm.getValue() || "");
    ds_houseblList.setCellData(0, "hhpcgb", lc_hhpcgb.getValue() || "");
    ds_houseblList.setCellData(0, "hhio", scwin.getHiddenHhio());
    ds_houseblList.setCellData(0, "inpid", scwin.userId);

    // Container
    for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
      ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
      ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue() || "");
      ds_ocContList.setCellData(i, "mhno", cnd_lc_mhno.getValue() || "");
      ds_ocContList.setCellData(i, "inpid", scwin.userId);
    }

    // EL
    for (var j = 0; j < ds_ocElList.getRowCount(); j++) {
      ds_ocElList.setCellData(j, "kcomcd", scwin.hd_kcomcd);
      ds_ocElList.setCellData(j, "hhblno", cnd_ed_hhblno.getValue() || "");
      ds_ocElList.setCellData(j, "mhno", cnd_lc_mhno.getValue() || "");
      ds_ocElList.setCellData(j, "inpid", scwin.userId);
      ds_ocElList.modifyRowStatus(j, "C"); // ds_ocElList.UserStatus(i)=1;  // insert 로 변경.
    }
  }

  // Booking Seq 필수
  if (lc_hhbkgseq.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Booking Seq"]); // @이(가) 존재하지 않습니다.
    return;
  }

  // Shipper/Consignee/Notify 길이 체크
  if (txt_hhs1.getValue().length > 100) {
    await $c.win.alert($p, "Shipper명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs1.getValue().length);
    txt_hhs1.focus();
    return;
  }
  if (txt_hhs2.getValue().length > 100) {
    await $c.win.alert($p, "Consignee명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs2.getValue().length);
    txt_hhs2.focus();
    return;
  }
  if (txt_hhs3.getValue().length > 100) {
    await $c.win.alert($p, "Notify명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + txt_hhs3.getValue().length);
    txt_hhs3.focus();
    return;
  }

  // MgntClnt 체크
  if (ds_clntNo.getRowCount() == 0) {
    ds_clntNo.insertRow(0);
    ds_clntNo.setRowPosition(0);
  }
  ds_clntNo.setCellData(0, "hhactcust", ed_hhactcust.getValue());
  let e = await $c.sbm.execute($p, sbm_retrieveMgntClnt);
  if (e.responseJSON.OUT_DS1.length > 0) {
    if (ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
      await $c.win.alert($p, "해당 Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
    }
  }

  // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
  if (ed_blpic.getValue() == "") {
    txt_blpic.setValue("");
    ds_houseblList.setCellData(0, "pic", scwin.userId);
  }
  $c.sbm.execute($p, sbm_save);
};

