scwin.f_addRow = async function (disGubun) {
  switch (disGubun) {
    case 1:
      // Container
      if ($c.util.isEmpty($p, cnd_ed_hhblno.getValue())) {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        return;
      }
      if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["HEADER"]); // @은(는) 필수 입력 항목입니다.
        return;
      }
      var row = ds_ocContList.getTotalRow();
      ds_ocContList.insertRow(row);
      ds_ocContList.setCellData(row, "kcomcd", scwin.hd_kcomcd);
      ds_ocContList.setCellData(row, "mchblno", cnd_ed_hhblno.getValue());
      ds_ocContList.setCellData(row, "mhno", cnd_lc_mhno.getValue() || "");
      ds_ocContList.setCellData(row, "inpid", scwin.userId);
      ds_ocContList.setCellData(row, "mcpart", "N");
      ds_ocContList.setCellData(row, "mcpkg", "0");
      ds_ocContList.setCellData(row, "mcwgt", "0");
      ds_ocContList.setCellData(row, "mcmsr", "0");
      gr_ocContList.setFocusedCell(row, "mccntno", true);
      break;
    case 2:
      // EL
      if ($c.util.isEmpty($p, cnd_ed_hhblno.getValue())) {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003);
        return;
      }
      if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["HEADER"]);
        return;
      }
      var row2 = ds_ocElList.getTotalRow();
      ds_ocElList.insertRow(row2);
      ds_ocElList.setCellData(row2, "kcomcd", scwin.hd_kcomcd);
      ds_ocElList.setCellData(row2, "hhblno", cnd_ed_hhblno.getValue());
      ds_ocElList.setCellData(row2, "mhno", cnd_lc_mhno.getValue() || "");
      ds_ocElList.setCellData(row2, "inpid", scwin.userId);
      ds_ocElList.setCellData(row2, "pgb", "N");
      ds_ocElList.setCellData(row2, "pkg", "0");
      ds_ocElList.setCellData(row2, "wgt", "0");
      ds_ocElList.setCellData(row2, "mpkg", "0"); //package
      ds_ocElList.setCellData(row2, "pseq", "0"); //분할선적차수

      gr_ocElList.setCellReadOnly(row2, "mpkg", true); //package
      gr_ocElList.setCellReadOnly(row2, "mut", true); //unit
      gr_ocElList.setCellReadOnly(row2, "pseq", true);
      gr_ocElList.setFocusedCell(row2, "elno", true); // gr_ocElList.setColumn("elno");
      break;
  }
};
