scwin.f_deleteRow = function (disGubun) {
  switch (disGubun) {
    case 1:
      // Container
      if (ds_ocContList.getRowCount() > 0) {
        var rowIdx = ds_ocContList.getRowPosition();
        if (ds_ocContList.getRowStatus(rowIdx) == "C") {
          ds_ocContList.removeRow(rowIdx);
        } else {
          ds_ocContList.deleteRow(rowIdx);
          ds_ocContList.setFocusedCell(rowIdx, 0);
        }
      }
      break;
    case 2:
      // El
      if (ds_ocElList.getRowCount() > 0) {
        var rowIdx = ds_ocElList.getRowPosition();
        if (ds_ocElList.getRowStatus(rowIdx) == "C") {
          ds_ocElList.removeRow(rowIdx);
        } else {
          ds_ocElList.deleteRow(rowIdx);
          ds_ocElList.setFocusedCell(rowIdx, 0);
        }
      }
      break;
  }
};

