scwin.f_validate = async function () {
  // VALIDATE
  if (!(await $c.gus.cfValidate($p, [ed_hhetd, ed_hhondt, ed_hheta, ed_hhisudt, ed_creadyDt], null, true))) {
    //validExp 가 yes일때 check
    return false;
  }

  // Booking No
  if ($c.util.isEmpty($p, ed_hhbkgno.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Booking No"]); // @은(는) 필수 입력 항목입니다.
    scwin.cfViewTab(0); // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
    ed_hhbkgno.focus();
    return false;
  }
  if ($c.util.isEmpty($p, lc_hhbkgseq.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Seq"]); // @은(는) 필수 입력 항목입니다.
    scwin.cfViewTab(0);
    lc_hhbkgseq.focus();
    return false;
  }
  if ($c.util.isEmpty($p, ed_hhetd.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["ETD"]); // @은(는) 필수 입력 항목입니다.
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }

  // 날짜 범위 확인
  if (!$c.util.isEmpty($p, ed_hheta.getValue())) {
    if (!(await $c.gus.cfIsAfterDate($p, ed_hhetd.getValue(), ed_hheta.getValue()))) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["ETD", "ETA"]);
      scwin.cfViewTab(0);
      ed_hhetd.focus();
      return false;
    }
  }

  // ETD가 저장일로부터 3개월 초과 미래 불가
  // if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate()) > 3) {
  //     await $c.win.alert("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
  //     scwin.cfViewTab(0);
  //     ed_hhetd.focus();
  //     return false;
  // }

  // ETA가 저장일로부터 3개월 초과 미래 불가
  // if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hheta.getValue().toDate()) > 3) {
  //     await $c.win.alert("ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
  //     scwin.cfViewTab(0);
  //     ed_hheta.focus();
  //     return false;
  // }

  // ETD가 3년 초과 과거 불가
  if ($c.gus.cfYearsBetween($p, ed_hhetd.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    await $c.win.alert($p, "ETD가 3년 이상의 과거 일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }

  // ETA가 3년 초과 과거 불가
  if ($c.gus.cfYearsBetween($p, ed_hheta.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    await $c.win.alert($p, "ETA가 3년 이상의 과거 일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hheta.focus();
    return false;
  }

  // ETA-ETD(transit time) 150일 초과 불가 (ETA-ETD + 1 <= 150  =>  (ETA-ETD) <= 149)
  if ($c.date.diffDate($p, ed_hhetd.getValue(), ed_hheta.getValue()) > 149) {
    await $c.win.alert($p, "ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }

  // Customer
  if ($c.util.isEmpty($p, ed_hhactcust.getValue()) || ed_hhactcust.getValue() == "999908") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Customer"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(0);
    ed_hhactcust.focus();
    return false;
  }
  if ($c.util.isEmpty($p, ed_hhbuyer.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(0);
    ed_hhbuyer.focus();
    return false;
  }
  if ($c.util.isEmpty($p, ed_hhitem.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(1);
    ed_hhitem.focus();
    return false;
  }
  if ($c.util.isEmpty($p, txt_hhmitem1.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item Name"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(1);
    txt_hhmitem1.focus();
    return false;
  }
  if ($c.util.isEmpty($p, txt_hhmitem2.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["EDI Item"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(1);
    txt_hhmitem2.focus();
    return false;
  }
  if ($c.util.isEmpty($p, ed_creadyDt.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Result Date"]); //@는 필수입력항목입니다.
    scwin.cfViewTab(0);
    ed_creadyDt.focus();
    return false;
  }

  // 신규시 DBEX가 아닌 DBEXxxxxx로 생성 못함.
  if (scwin.statusFlag == "C") {
    if (cnd_ed_hhblno.getValue().length != 4 && cnd_ed_hhblno.getValue().substring(0, 4) == "DBEX") {
      // !=4 에서 수정
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_026, ["Auto Create", "DBEX"]); // @은(는) '@' 형식이어야 합니다.
      cnd_ed_hhblno.focus();
      return false;
    }
  }

  // 거래처별 매출귀속 일치여부 확인
  dma_customerInfo.set("sysCd", "ilCommonEBC");
  dma_customerInfo.set("queryId", "retriveCustomerInfo");
  dma_customerInfo.set("param1", ed_hhactcust.getValue());
  let e = await $c.sbm.execute($p, sbm_customerInfo);
  if (e.responseJSON.GAUCE.length > 0) {
    // if (ds_customerInfo.getRowCount() > 0) {
    if (ed_hhbuyer.getValue() != ds_customerInfo.getCellData(0, "col1")) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_007);
      scwin.cfViewTab(0);
      ed_hhbuyer.focus();
      return false;
    }
  }

  // Container Type 중복 체크
  if (!(await scwin.f_containerDualCheck())) {
    return false;
  }

  // Container/EL 필수값 체크는 [TODO] ds_ocContList/ds_ocElList 루프 구현
  // Container Type value check
  const cntTypeEdits = [ed_hhcnt1type, ed_hhcnt2type, ed_hhcnt3type, ed_hhcnt4type];
  for (const ed of cntTypeEdits) {
    const v = ed.getValue();
    if (!$c.util.isEmpty($p, v)) {
      const tmp = ds_containerType.getMatchedColumnData("code", v, "code");
      if (!tmp || tmp.length < 1) {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Container Type"]);
        scwin.cfViewTab(0);
        ed.focus();
        return false;
      }
    }
  }

  // Container
  for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
    if ($c.util.isEmpty($p, ds_ocContList.getCellData(i, "mccntno"))) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Container"]); //@는 필수입력항목입니다.
      gr_ocContList.focus();
      gr_ocContList.setFocusedCell(i, "mccntno", true); // mccntno
      return false;
    }
  }

  // 수출신고번호
  scwin.v_elno = "";
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    if (ds_ocElList.getCellData(i, "elno") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["수출신고번호"]); //@는 필수입력항목입니다.
      gr_ocElList.setFocusedCell(i, "elno");
      return false;
    }
  }

  // unit
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    if (ds_ocElList.getCellData(i, "unit") == "") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
      gr_ocElList.setFocusedCell(i, "unit");
      return false;
    }
  }

  // Package
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    var pkg = ds_ocElList.getCellData(i, "pkg");
    if (pkg == "" || Number(pkg) == "0") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Package"]); //@는 필수입력항목입니다.
      gr_ocElList.setFocusedCell(i, "pkg");
      return false;
    }
  }

  // Weight
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    var wgt = ds_ocElList.getCellData(i, "wgt");
    if (wgt == "" || Number(wgt) == "0") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Weight"]); //@는 필수입력항목입니다.
      gr_ocElList.setFocusedCell(i, "wgt");
      return false;
    }
  }

  // 포장기호
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    if (ds_ocElList.getCellData(i, "mgb") != "") {
      var mpkg = ds_ocElList.getCellData(i, "mpkg");
      if (mpkg == "" || Number(mpkg) == "0") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["package"]); //@는 필수입력항목입니다.
        gr_ocElList.setFocusedCell(i, "mpkg");
        return false;
      }
      var mut = ds_ocElList.getCellData(i, "mut");
      if (mut == "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
        gr_ocElList.setFocusedCell(i, "mut");
        return false;
      }
    }
  }

  // 분할
  for (var i = 0; i < ds_ocElList.getTotalRow(); i++) {
    if (ds_ocElList.getCellData(i, "pgb") == "Y") {
      if (ds_ocElList.getCellData(i, "pseq") == "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["ISO"]); //@는 필수입력항목입니다.
        gr_ocElList.setFocusedCell(i, "pseq");
        return false;
      }
    }
  }

  // Cargo Type Check (Bulk + Container 입력)
  if (lc_hhbltype.getValue() == "B" && (ed_hhcnt1.getValue() != "0" || ed_hhcnt2.getValue() != "0" || ed_hhcnt3.getValue() != "0" || ed_hhcnt4.getValue() != "0")) {
    const msg = "Cargo Type이 Bulk 이면서 Container정보가 입력되었습니다.\n입력된 정보가 맞으시면 확인처리 해 주십시오.";
    const ok = await $c.win.confirm($p, msg);
    if (!ok) {
      ed_hhcnt1.focus();
      return false;
    }
  }

  // EDI ITEM 글자수 및 특수문자 여부 CHECK
  if (!scwin.cf_ChkInputOnlyNumberAndAlphabet(txt_hhmitem2.getValue())) {
    await $c.win.alert($p, "EDI ITEM에 특수문자만 입력은 불가능합니다.");
    return false;
  }
  if ($c.gus.cfGetByteLength($p, txt_hhmitem2.getValue()) < 2) {
    await $c.win.alert($p, "EDI ITEM에 2글자 이상을 입력하셔야합니다.");
    return false;
  }
  return true;
};

// 추가) 영숫자인지 확인 
scwin.cf_ChkInputOnlyNumberAndAlphabet = function (value) {
  if (!value) return false;

  // 공백 제거
  const chr = value.replace(/\s+/g, "");

  // 한 글자라도 영문/숫자가 포함되어 있으면 true
  for (let i = 0; i < chr.length; i++) {
    const code = chr.charCodeAt(i);

    // a~z
    if (code >= 0x61 && code <= 0x7A) return true;

    // A~Z
    if (code >= 0x41 && code <= 0x5A) return true;

    // 0~9
    if (code >= 0x30 && code <= 0x39) return true;
  }

  // 영문/숫자가 하나도 없고 특수문자만 있으면 false
  return false;
};

// 추가 
scwin.f_chkPopUp = function (inObj, pairObj, isCode, disGubun, chgGubun) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_PopUp(disGubun, chgGubun);
  } else {
    scwin.f_PopUp(disGubun, chgGubun);
  }
};

