//---------------------------------------------------------
// Cargo Control
// 숫자를 영문으로 변환하거나 다른 포멧으로 변경한다.
//---------------------------------------------------------
scwin.f_cargoControl = function () {
  if (scwin.statusFlag == "C" || scwin.statusFlag == "U") {
    if (lc_hhbltype.getValue() == "F") {
      txt_hhsubpkg.setValue("");
      txt_hhunit2.setValue("");
      txt_hhsay.setValue("");
      let result = "";
      let resultSay = "";
      let resultCnt = 0;
      const nameByCode = code => {
        const idx = ds_containerType.getMatchedIndex("code", code);
        return idx < 0 ? "" : ds_containerType.getCellData(idx, "name");
      };
      const add = (typeCode, qty, prevQty) => {
        if ($c.util.isEmpty($p, typeCode) || $c.util.isEmpty($p, qty) || qty == "0") return 0;
        const nm = nameByCode(typeCode);
        if ($c.util.isEmpty($p, nm)) return 0;
        const strc = nm + " X " + qty;
        if ($c.util.isEmpty($p, result)) {
          result = strc;
          resultSay = scwin.cf_NumChangeEng(qty) + "(" + strc + ")";
        } else {
          result = result + " & " + strc;
          resultSay = resultSay + " & " + scwin.cf_NumChangeEng(qty) + "(" + strc + ")";
        }
        return parseInt(qty, 10) || 0;
      };
      resultCnt += add(ed_hhcnt1type.getValue(), ed_hhcnt1.getValue());
      resultCnt += add(ed_hhcnt2type.getValue(), ed_hhcnt2.getValue());
      resultCnt += add(ed_hhcnt3type.getValue(), ed_hhcnt3.getValue());
      resultCnt += add(ed_hhcnt4type.getValue(), ed_hhcnt4.getValue());
      txt_hhsubpkg.setValue(result);

      // Number of Containers or Packages2
      if (!$c.util.isEmpty($p, ed_hhpkg.getValue()) && ed_hhpkg.getValue() !== "0") {
        txt_hhunit2.setValue(ed_hhpkg.getValue() + " " + txt_hhunit.getValue());
      }

      // Say
      if (resultCnt == 1) {
        txt_hhsay.setValue(resultSay + " CONTAINER ONLY");
      } else {
        txt_hhsay.setValue(resultSay + " CONTAINERS ONLY");
      }

      // Print option
      chb_hhp1.setValue("1");
      chb_hhp2.setValue("1");
      chb_hhp3.setValue("1");
    } else if (lc_hhbltype.getValue() == "L") {
      txt_hhsubpkg.setValue("");
      txt_hhunit2.setValue("");
      txt_hhsay.setValue("");

      // Number of Containers or Packages
      if (!$c.util.isEmpty($p, ed_hhpkg.getValue()) && ed_hhpkg.getValue() != "0") {
        txt_hhsubpkg.setValue(ed_hhpkg.getValue() + " " + txt_hhunit.getValue());
      }

      // Say
      if (!$c.util.isEmpty($p, ed_hhpkg.getValue()) && ed_hhpkg.getValue() != "0") {
        const v = scwin.cf_NumChangeEng(ed_hhpkg.getValue());
        if (ed_hhpkg.getValue() == "1") {
          txt_hhsay.setValue(v + "(" + ed_hhpkg.getValue() + ") " + txt_hhunit.getValue() + " ONLY");
        } else {
          txt_hhsay.setValue(v + "(" + ed_hhpkg.getValue() + ") " + txt_hhunit.getValue() + "'S ONLY");
        }
      }

      // Print option
      chb_hhp1.setValue("0");
      chb_hhp2.setValue("1");
      chb_hhp3.setValue("0");
    } else {
      return;
    }
  }
};

