//---------------------------------------------------------
// 수출신고번호 Check
//---------------------------------------------------------
scwin.f_elnoExportCheck = async function (elno) {
  if ($c.util.isEmpty($p, elno) || !/^\d{15}$/.test(elno)) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_038, ["수출신고번호"]);
    return false;
  }
  const chkCode = elno.charCodeAt(14) - 48; // 0~9
  const weights = [7, 3, 1, 7, 3, 1, 7, 3, 1, 7, 3, 1, 7, 3];
  let sum = 0;
  for (let i = 0; i < 14; i++) {
    const d = elno.charCodeAt(i) - 48;
    sum += d * weights[i] % 10;
  }
  let result = sum % 10;
  if (result > 0) result = 10 - result;
  if (chkCode !== result) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_038, ["수출신고번호"]);
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// 화물관리번호  Check
//-------------------------------------------------------------------------
scwin.f_elnoReshipmentCheck = async function (elno) {
  // 11자리 숫자(0~10), 10번째가 체크자리
  if ($c.util.isEmpty($p, elno) || !/^\d{11}$/.test(elno)) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_038, ["화물관리번호"]);
    return false;
  }
  const chkCode = elno.charCodeAt(10) - 48; // '0'~'9' -> 0~9
  const weights = [3, 7, 9, 3, 7, 9, 3, 7, 9, 3];
  let sum = 0;
  for (let i = 0; i < 10; i++) {
    const d = elno.charCodeAt(i) - 48;
    sum += d * weights[i] % 10;
  }
  const result = sum % 10;
  if (chkCode !== result) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_038, ["화물관리번호"]);
    return false;
  }
  return true;
};

