//---------------------------------------------------------
scwin.f_departmentChange = async function () {
  if (ed_hhbuyer.getValue() != "") {
    var opts = {
      id: "",
      popupName: "",
      modal: true,
      type: "browserPopup" //화면 오픈 타입 ("pageFramePopup", "browserPopup")
      ,
      title: "Department Change" //Layer pop
      ,
      popupName: "Department Change",
      width: 460,
      height: 280
    };
    var data = {
      pdept: ed_hhbuyer.getValue(),
      pdeptnm: txt_hhbuyernm.getValue()
    };
    var rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonDeptChange.xml", opts, data);
    // rtnList[0] = "N/A" ;
    // rtnList[1] = ed_newdept.Text;
    // rtnList[2] = txt_newdeptnm.value;

    if (rtnList != null) {
      if (rtnList[0] == "N/A" && rtnList[1] != "" && rtnList[2] != "") {
        // 부서 변경  프로시저 호출 시작
        ds_DeptChangeParam.removeAll();
        ds_DeptChangeParam.insertRow(0);
        ds_DeptChangeParam.setCellData(0, "modrNo", "");
        ds_DeptChangeParam.setCellData(0, "hodrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo")); // Order No
        ds_DeptChangeParam.setCellData(0, "kcomcd", scwin.hd_kcomcd); // 법인코드
        ds_DeptChangeParam.setCellData(0, "bulkGb", ""); // bulk여부
        ds_DeptChangeParam.setCellData(0, "dept", rtnList[1]); // 변경할 부서 코드
        ds_DeptChangeParam.setCellData(0, "deptnm", rtnList[2]); // 변경할 부서  명

        var spMsg = "";
        var spRtn = "-1";
        if (await $c.win.confirm($p, E_MSG_CM_CRM_001)) {
          //저장하시겠습니까?
          let e = await $c.sbm.execute($p, sbm_DeptChange);
          if (e.responseJSON.OUT_DS1.length > 0) {
            ds_DeptChangeResult.setRowPosition(0);
            spMsg = ds_DeptChangeResult.getCellData(ds_DeptChangeResult.getRowPosition(), "spMsg");
            spRtn = ds_DeptChangeResult.getCellData(ds_DeptChangeResult.getRowPosition(), "spRtn");
            if (spRtn == "0") {
              //변경 성공
              txt_hhbuyernm.setValue(rtnList[2]);
              ed_hhbuyer.setValue(rtnList[1]);
              await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_009);
            } else if (spRtn == "-2") {
              //Customer와 Dept가 일치하지 않습니다.
              await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_007);
            } else {
              await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_008);
            }
          }
        }
        // 부서 변경  프로시저 호출 끝
      }
    }
  }
};

